function set_controls ()
{
if (Ctrl('l_convenio'))
{
	if (Ctrl('l_convenio').GetXValue() == '1')
	{		
		Ctrl('oi_banda_sal').SetCValue("");		
		CtrlEnabled('oi_banda_sal', false);
		CtrlEnabled('oi_categoria', true);			
	}
	else
	{
		Ctrl('oi_categoria').SetCValue("");		
		CtrlEnabled('oi_categoria', false);		
		CtrlEnabled('oi_banda_sal', true);			
	}
}
}
